const api=(p,o={})=>{o=o||{};const method=String(o.method||'GET').toUpperCase();const headers=Object.assign({'Content-Type':'application/json'},o.headers||{});if(csrfToken&&method!=='GET')headers['X-CSRF-Token']=csrfToken;return fetch(p,{...o,headers}).then(async r=>{const t=await r.text();let j;try{j=JSON.parse(t)}catch(e){j={success:r.ok,text:t}}if(!r.ok||j.success===false)throw new Error(j.error||t);return j})};
const esc=s=>String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));
const msg=(s)=>document.getElementById('msg').textContent=s;
