async function checkApp(){const st=document.getElementById('adminAppStatus');const was=adminAppReady;try{const r=await fetch('/api/ping',{cache:'no-store'});if(r.ok){adminAppReady=true;try{const sr=await fetch('/api/auth/session',{cache:'no-store'});const sj=await sr.json();if(sj&&sj.csrf_token)csrfToken=sj.csrf_token}catch(_e){}if(st){st.className='status ok';if(st.dataset.label)st.textContent=st.dataset.label}return true}}catch(e){}adminAppReady=false;if(st){st.className='status bad';st.textContent='Unavailable'}if(was)msg('Application unavailable. System Configuration editing, reference-data saves, pricing refresh, and diagnostics are unavailable until the app restarts.');return false}
